import{_ as s,o as l,c as n,O as t}from"./chunks/framework.47655c42.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"product/deployment.md","filePath":"product/deployment.md","lastUpdated":1775907908000}'),r={name:"product/deployment.md"};function i(e,a,c,p,d,o){return l(),n("div",null,a[0]||(a[0]=[t('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Deployment</p><h1>部署方式</h1><div class="brand-hero__panel"><span class="brand-pill">Deployment Thesis</span><strong>控制面可以统一，执行位置不必统一。</strong><p>这正是 ExecGov 当前能同时承接正式交付、公开体验和本地接入的关键原因。</p></div><p class="brand-lead"> ExecGov 的部署思路不是只有一种，而是根据 <strong>数据边界、客户规模和执行位置</strong> 做组合。 平台的目标不是强迫所有用户走同一条路径，而是用同一套治理逻辑覆盖不同落地形态。 </p><div class="brand-chip-list"><span class="brand-chip">单租户交付</span><span class="brand-chip">平台治理</span><span class="brand-chip">免费入口</span><span class="brand-chip">本地混合执行</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../contact.html#lead-form">沟通部署方案</a><a class="cta-button" href="./editions.html">查看版本路线</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // DEPLOYMENT MATRIX</span><span>DOC 05</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">enterpriseMode</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__string">&#39;single_tenant_delivery&#39;</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">platformMode</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;public_governance&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;free_entry&#39;</span><span class="matrix-panel__punct">]</span></span><span class="matrix-panel__line"><span class="matrix-panel__kw">const</span> <span class="matrix-panel__ident">hybridMode</span> <span class="matrix-panel__op">=</span> <span class="matrix-panel__punct">[</span><span class="matrix-panel__string">&#39;local_execution&#39;</span><span class="matrix-panel__punct">,</span> <span class="matrix-panel__string">&#39;cli_bridge&#39;</span><span class="matrix-panel__punct">]</span></span></div><div class="matrix-panel__callout">ONE GOVERNANCE / MULTIPLE DEPLOYMENTS</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">surface</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">cloud</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">surface</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">local</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">surface</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">hybrid</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">01</p><h2>单租户交付模式</h2><ul class="brand-list"><li>适合企业客户项目交付</li><li>需要独立访问地址</li><li>需要和其他客户完全隔离</li><li>一个客户一个租户，能力与数据边界清晰</li></ul></article><article class="brand-card"><p class="brand-kicker">02</p><h2>平台治理模式</h2><ul class="brand-list"><li>平台方统一管理多个客户</li><li>需要公告、模板、日志和台账总控</li><li>需要跨租户治理但不打破隔离</li><li><code>public</code> 作为平台治理域</li></ul></article><article class="brand-card"><p class="brand-kicker">03</p><h2>免费入口模式</h2><ul class="brand-list"><li>适合产品体验入口和个人开发者试用</li><li>更强调上手速度和体验路径</li><li>为后续更深沟通和正式交付提供前置入口</li></ul></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">04</p><h2>本地混合执行模式</h2><ul class="brand-list"><li>适合文件和数据不能全部上云</li><li>任务依赖本地环境或内网资源</li><li>平台负责入口、规划、权限和审计</li><li>本地环境负责执行，CLI / Agent 负责桥接</li></ul></article><article class="brand-card"><p class="brand-kicker">05</p><h2>当前公开重点之外的路线</h2><ul class="brand-list"><li>当前公开重点不是设备、边缘或插件治理</li><li>Agent 常驻执行仍属于后续增强，不是现在的公开卖点</li><li>先把真实项目里的本地执行和内网接入做好更重要</li><li>更远路线等有真实需求再继续展开</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Upgrade Path</p><h2>从免费入口到正式交付，当前更真实的升级路径</h2><table><thead><tr><th>阶段</th><th>当前状态</th><th>更适合的部署理解</th><th>下一步信号</th></tr></thead><tbody><tr><td>01. 公开体验期</td><td>先看公开体验页、登录页、注册页和公开文档</td><td>这时重点不是一开始就谈私有化，而是先确认执行链路、产品定位和入口体验是否成立</td><td>如果要反复使用，就进入免费入口或继续做方案沟通</td></tr><tr><td>02. 个人免费入口期</td><td>用户已经进入免费入口，开始理解智能执行台、AI 执行和基础使用路径</td><td>这时更接近产品体验与增长入口，不等于已经进入正式团队 / 企业交付</td><td>如果开始关心多人协作、客户隔离、正式验收，就进入评估期</td></tr><tr><td>03. 方案评估期</td><td>开始带着真实脚本型能力、真实场景、真实权限问题来沟通</td><td>这时通常要同时看 <a href="./customer-flow.html">客户流程 / 交付</a>、<a href="./cli.html">CLI 指引</a> 和部署方式，而不是只看免费线路</td><td>如果需要独立网址、独立租户和正式验收，就进入单租户交付</td></tr><tr><td>04. 正式交付期</td><td>客户要拿到自己的访问地址、自己的能力边界和正式交付包</td><td>当前主线是单租户交付：一个客户一个租户，一个客户一个网址</td><td>如果要统一管理多个客户，再叠加平台治理能力</td></tr><tr><td>05. 本地扩展期</td><td>任务开始依赖本地环境、内网资源或私有数据</td><td>在单租户交付或平台治理之上叠加本地混合执行，由 CLI / Agent 承接桥接</td><td>如果还要进一步走标准化梯度，就看 <a href="./editions.html">版本路线</a></td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Upgrade Signal</p><h2>哪些信号说明你该从免费入口升级到正式交付</h2><ul class="brand-list"><li>需要一个客户自己的正式访问网址</li><li>需要独立租户和更明确的数据 / 能力隔离</li><li>需要正式账号、权限、验收和后续更新说明</li><li>需要把真实脚本型能力、真实业务场景和真实审批边界接入平台</li><li>需要把平台从体验入口变成可持续交付空间</li></ul></article><article class="brand-card"><p class="brand-kicker">Recommended Path</p><h2>常见升级路径</h2><ul class="brand-list"><li>免费入口适合先体验平台与执行链路</li><li>正式交付适合需要独立网址、租户隔离和长期使用的场景</li><li>标准化小团队方案和更完整的套餐能力会继续扩展</li><li>常见路径是先体验，再进入试用或正式交付</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Deployment Prep</p><h2>部署评估前，通常先对齐这 3 件事</h2><div class="brand-link-grid"><a class="brand-link-card" href="./file-results.html"><span>Files</span><strong>文件上传 / 结果下载</strong><p>如果项目依赖输入文件、批次状态、Excel 结果或导出产物，先把文件链路说明清楚，再谈部署方式会更稳。</p></a><a class="brand-link-card" href="./deliverables.html"><span>Deliverables</span><strong>交付物 / 文档入口</strong><p>正式交付评估通常会先明确客户最终拿到什么网址、什么账号、什么说明和什么结果入口。</p></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Checklist</span><strong>客户接入准备清单</strong><p>已有真实脚本型能力和真实场景时，先把脚本目录、README、样例文件、依赖和风险边界准备好，会更容易完成部署判断。</p></a></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Standard Delivery</p><h2>标准交付内容</h2><ul class="brand-list"><li>一个独立租户</li><li>一个独立访问网址</li><li>一组客户专属能力，当前通常以脚本型能力为主</li><li>平台账号与基础权限</li><li>客户使用说明与脚本热更新说明</li></ul></article><article class="brand-card"><p class="brand-kicker">Standard Scope</p><h2>当前默认不包含什么</h2><ul class="brand-list"><li>公开第三方能力市场</li><li>客户绕过平台自行发布脚本</li><li>无审批的高风险自动执行</li><li>打破租户边界的跨客户能力共享</li></ul></article></section><section class="brand-card"><p class="brand-kicker">How To Choose</p><h2>按项目重点进入合适的部署路径</h2><div class="brand-link-grid"><a class="brand-link-card" href="../contact.html#lead-form"><span>Customer Delivery</span><strong>客户交付型项目</strong><p>优先单租户交付模式，再视情况补统一治理能力。</p></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Platform Ops</span><strong>平台治理与运营</strong><p>在租户隔离之上叠加平台治理模式，统一公告、模板、日志和台账。</p></a><a class="brand-link-card" href="./customer-flow.html"><span>Delivery Ops</span><strong>客户上线与后续更新</strong><p>直接看客户流程 / 交付页，把标准交付包、使用路径、热更新和验收重点一次看清。</p></a><a class="brand-link-card" href="./file-results.html"><span>File Flow</span><strong>如果项目核心是文件处理和结果产物</strong><p>先把上传输入文件、批次状态和结果下载的公开链路讲清楚，再决定是云端处理还是混合执行。</p></a><a class="brand-link-card" href="./deliverables.html"><span>Delivery Kit</span><strong>正式交付包与说明入口</strong><p>继续看交付物 / 文档入口页，把客户长期使用时真正能拿到的说明和入口一次说清。</p></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Growth Entry</span><strong>获客与试用入口</strong><p>加上免费入口模式，让访客可以先体验，再进入场景沟通或正式交付路径。</p></a><a class="brand-link-card" href="./cli.html"><span>CLI Bridge</span><strong>本地环境与内网执行</strong><p>先看 CLI 指引，把 <code>login / register / run / agent</code> 的当前接入边界和落地路径跑通。</p></a><a class="brand-link-card" href="./onboarding-checklist.html"><span>Ready First</span><strong>接入资料尚未齐备</strong><p>先回到接入准备清单，而不是急着先选私有化、平台治理或本地桥接其中一种部署标签。</p></a><a class="brand-link-card" href="./editions.html"><span>Current Stage</span><strong>当前阶段与下一步重点</strong><p>先回到当前阶段说明，确认哪些是现在能做的，哪些还不该讲太满。</p></a></div></section></div>',1)]))}const h=s(r,[["render",i]]);export{m as __pageData,h as default};
